### `apps/org-next/tests/test-fixture.ts`

```1:42:/Users/duhl/git/ui/apps/org-next/tests/test-fixture.ts
import { test as base } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";

export const test = base.extend<{ mockServerRequest: MockClient }>({
  mockServerRequest: async ({ context }, use) => {
    const mockClient = new MockClient();
    mockClient.onChange = async (headers) =>
      context.setExtraHTTPHeaders(headers);
    await use(mockClient);
  },
  page: async ({ page, baseURL, context }, use) => {
    const localOrigin = baseURL ? new URL(baseURL).origin : undefined;
    const isSpecialScheme = (url: string) =>
      url.startsWith("about:") ||
      url.startsWith("blob:") ||
      url.startsWith("data:");

    await context.route("**/*", async (route) => {
      const requestUrl = route.request().url();
      if (!localOrigin || isSpecialScheme(requestUrl)) {
        await route.continue();
        return;
      }

      const requestOrigin = new URL(requestUrl).origin;
      if (requestOrigin === localOrigin) {
        await route.continue();
        return;
      }

      await route.abort();
      throw new Error(
        `[Playwright] Blocked external browser request: ${route.request().method()} ${requestUrl}\n All requests to external APIs must flow through server functions`,
      );
    });

    await use(page);
    await context.unroute("**/*");
  },
});

export { expect } from "@playwright/test";
```

### `packages/test-utils/src/request-mocking.ts` (MSW Node server for RMP)

```1:24:/Users/duhl/git/ui/packages/test-utils/src/request-mocking.ts
import { getRequestHeaders } from "@tanstack/start-server-core";
import { setupServer } from "msw/node";
import { createHandler } from "request-mocking-protocol/msw";

export function setupRequestMocking() {
  const mockHandler = createHandler(() => {
    return getRequestHeaders();
  });

  // Type mismatch stems from MSW's split type declarations (core vs node). Safe to cast.
  const mswServer = setupServer(
    mockHandler as unknown as Parameters<typeof setupServer>[0],
  );
  mswServer.listen({
    onUnhandledRequest(request) {
      console.error(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
      throw new Error(
        `[MSW] Unhandled request: ${request.method} ${request.url}`,
      );
    },
  });
}
```

### `packages/test-utils/src/setup.ts` (optional Vitest MSW lifecycle — not wired in org-next)

```1:72:/Users/duhl/git/ui/packages/test-utils/src/setup.ts
import { cleanup } from "@testing-library/react";
import type { RequestHandler } from "msw";
import { type SetupServer, setupServer } from "msw/node";
import { afterAll, afterEach, beforeAll } from "vitest";

/**
 * Configuration for the test utils.
 *
 * This config is used to configure the test utils to work with your specific project.
 * It is used to configure the MSW handlers and the providers to wrap the test components.
 * It is also used to configure the additional setup to run before all tests, after each test, and after all tests.
 */

export interface TestUtilsConfig {
  /**
   * Project-specific MSW handlers
   */
  handlers?: RequestHandler[];
  /**
   * Project-specific providers to wrap test components
   */
  providers?: React.ComponentType<{ children: React.ReactNode }>[];
  /**
   * Additional setup to run before all tests
   */
  beforeAll?: () => void | Promise<void>;
  /**
   * Additional setup to run after each test
   */
  afterEach?: () => void | Promise<void>;
  /**
   * Additional setup to run after all tests
   */
  afterAll?: () => void | Promise<void>;
}

let server: SetupServer;

export function setupTestUtils(config: TestUtilsConfig = {}) {
  // Setup MSW server with project-specific handlers
  server = setupServer(...(config.handlers || []));

  // Setup global test hooks
  beforeAll(async () => {
    server.listen();
    await config.beforeAll?.();
  });

  afterEach(() => {
    cleanup();
    server.resetHandlers();
    config.afterEach?.();
  });

  afterAll(async () => {
    server.close();
    await config.afterAll?.();
  });

  return {
    providers: config.providers || [],
    server,
  };
}

// Export a hook to access the server in tests
export function useTestServer() {
  if (!server) {
    throw new Error("Test server not initialized. Call setupTestUtils first.");
  }
  return server;
}
```

